// billWarehouseComboboxData returns the Alpine x-data body. Pulled
// out into its own Go helper so the backtick string doesn't choke the
// templ parser (same shape as creditNoteFormData).
func billWarehouseComboboxData() string {
	return `{
		warehouses: [],
		filtered: [],
		query: '',
		selectedId: '',
		selectedLabel: '',
		open: false,
		highlighted: 0,
		init() {
			try { this.warehouses = JSON.parse(this.$el.dataset.warehouses || '[]'); } catch (e) { this.warehouses = []; }
			this.filtered = this.warehouses.slice();
			var initId = this.$el.dataset.initialId || '';
			if (initId) {
				var found = null;
				for (var i = 0; i < this.warehouses.length; i++) {
					if (String(this.warehouses[i].id) === String(initId)) { found = this.warehouses[i]; break; }
				}
				if (found) { this.selectedId = String(found.id); this.selectedLabel = found.label; this.query = found.label; }
			}
		},
		filter() {
			var q = (this.query || '').toLowerCase().trim();
			if (!q) { this.filtered = this.warehouses.slice(); }
			else {
				this.filtered = this.warehouses.filter(function(w){
					return (w.search || '').indexOf(q) !== -1 || (w.label || '').toLowerCase().indexOf(q) !== -1;
				});
			}
			if (this.query !== this.selectedLabel) { this.selectedId = ''; }
			this.highlighted = 0;
			this.open = true;
		},
		move(delta) {
			if (!this.open) { this.open = true; return; }
			var n = this.filtered.length;
			if (n === 0) return;
			this.highlighted = (this.highlighted + delta + n) % n;
		},
		pick(w) {
			this.selectedId = String(w.id);
			this.selectedLabel = w.label;
			this.query = w.label;
			this.open = false;
		},
		pickHighlighted() {
			if (this.filtered[this.highlighted]) { this.pick(this.filtered[this.highlighted]); }
		}
	}`
}

